#include <stdlib.h>
#include <string.h>

typedef struct {
    void (*func)();
    char name[16];
} Object;

void legit() {
    printf("Legit function\n");
}

void evil() {
    printf("Evil function!\n");
}

int main() {
    Object *obj = malloc(sizeof(Object));
    obj->func = legit;
    strcpy(obj->name, "test");
    free(obj);  // 释放
    // 未置空，后续使用
    Object *fake = malloc(sizeof(Object));
    fake->func = evil;  // 攻击者控制
    obj->func();  // UAF，实际调用evil
    return 0;
}
```
